import{_ as r,o as a,c as o,a4 as l}from"./chunks/framework.ChErgFjV.js";const b=JSON.parse('{"title":"初二数学知识体系","description":"","frontmatter":{"title":"初二数学知识体系","date":"2026-07-03T00:00:00.000Z","tags":["初中数学","八年级","广州中考"]},"headers":[],"relativePath":"math-junior/grade8.md","filePath":"math-junior/grade8.md","lastUpdated":1783070042000}'),n={name:"math-junior/grade8.md"};function e(i,t,s,d,h,g){return a(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="初二数学知识体系-八年级" tabindex="-1">初二数学知识体系（八年级） <a class="header-anchor" href="#初二数学知识体系-八年级" aria-label="Permalink to &quot;初二数学知识体系（八年级）&quot;">​</a></h1><blockquote><p>🔴 <strong>中考高频</strong>　🟡 <strong>中考常考</strong>　🟢 <strong>基础掌握</strong></p><p>初二是初中数学的分水岭，几何推理和函数思想全面引入，广州中考中初二内容的占比超过 40%。</p></blockquote><hr><h2 id="八年级上册" tabindex="-1">八年级上册 <a class="header-anchor" href="#八年级上册" aria-label="Permalink to &quot;八年级上册&quot;">​</a></h2><h3 id="第十一章-三角形-🔴" tabindex="-1">第十一章 三角形 🔴 <a class="header-anchor" href="#第十一章-三角形-🔴" aria-label="Permalink to &quot;第十一章 三角形 🔴&quot;">​</a></h3><blockquote><p>🔴 <strong>中考高频</strong>：三角形是平面几何的基石，中考必考。</p></blockquote><h4 id="_11-1-与三角形有关的线段-🟡" tabindex="-1">11.1 与三角形有关的线段 🟡 <a class="header-anchor" href="#_11-1-与三角形有关的线段-🟡" aria-label="Permalink to &quot;11.1 与三角形有关的线段 🟡&quot;">​</a></h4><p><strong>知识点</strong>：三角形的分类；三角形三边关系；三角形的中线、高、角平分线。</p><p><strong>案例</strong>：</p><ul><li>三边关系：下列能组成三角形的是？ <ul><li>A. 2, 3, 6 → 2+3&lt;6 ✗</li><li>B. 3, 4, 5 → 3+4&gt;5 ✓</li><li>C. 1, 2, 3 → 1+2=3 ✗（不能等于）</li></ul></li><li>三角形两边长为 3 和 7，第三边 x 的范围：<strong>4 &lt; x &lt; 10</strong></li></ul><h4 id="_11-2-与三角形有关的角-🔴" tabindex="-1">11.2 与三角形有关的角 🔴 <a class="header-anchor" href="#_11-2-与三角形有关的角-🔴" aria-label="Permalink to &quot;11.2 与三角形有关的角 🔴&quot;">​</a></h4><p><strong>知识点</strong>：三角形内角和定理；外角性质（外角 = 不相邻两内角之和）。</p><p><strong>案例</strong>：</p><ul><li>△ABC 中，∠A = 50°，∠B = 70°，则∠C = <strong>60°</strong>，外角 ∠ACD = <strong>120°</strong></li><li>外角定理推论：三角形的一个外角大于任何一个与它不相邻的内角</li></ul><h4 id="_11-3-多边形及其内角和-🟡" tabindex="-1">11.3 多边形及其内角和 🟡 <a class="header-anchor" href="#_11-3-多边形及其内角和-🟡" aria-label="Permalink to &quot;11.3 多边形及其内角和 🟡&quot;">​</a></h4><p><strong>知识点</strong>：n 边形内角和 = (n-2)×180°；外角和 = 360°。</p><p><strong>案例</strong>：</p><ul><li>八边形内角和 = (8-2)×180° = <strong>1080°</strong></li><li>一个多边形的内角和为 720°，则边数 n = <strong>6</strong></li></ul><hr><h3 id="第十二章-全等三角形-🔴🔴" tabindex="-1">第十二章 全等三角形 🔴🔴 <a class="header-anchor" href="#第十二章-全等三角形-🔴🔴" aria-label="Permalink to &quot;第十二章 全等三角形 🔴🔴&quot;">​</a></h3><blockquote><p>🔴🔴 <strong>中考核心</strong>：全等三角形是几何证明的核心工具，广州中考几何大题几乎必涉及全等。</p></blockquote><h4 id="_12-1-全等三角形的性质" tabindex="-1">12.1 全等三角形的性质 <a class="header-anchor" href="#_12-1-全等三角形的性质" aria-label="Permalink to &quot;12.1 全等三角形的性质&quot;">​</a></h4><p><strong>知识点</strong>：全等三角形对应边相等、对应角相等。</p><h4 id="_12-2-三角形全等的判定-🔴" tabindex="-1">12.2 三角形全等的判定 🔴 <a class="header-anchor" href="#_12-2-三角形全等的判定-🔴" aria-label="Permalink to &quot;12.2 三角形全等的判定 🔴&quot;">​</a></h4><table tabindex="0"><thead><tr><th>判定方法</th><th>条件</th><th>适用说明</th></tr></thead><tbody><tr><td>SSS</td><td>三边对应相等</td><td>任何三角形</td></tr><tr><td>SAS</td><td>两边及夹角对应相等</td><td>注意&quot;夹角&quot;</td></tr><tr><td>ASA</td><td>两角及夹边对应相等</td><td>任何三角形</td></tr><tr><td>AAS</td><td>两角及对边对应相等</td><td>任何三角形</td></tr><tr><td>HL</td><td>斜边和一直角边对应相等</td><td>仅直角三角形</td></tr></tbody></table><blockquote><p>⚠️ <strong>易错</strong>：SSA 不能判定全等（两边及其中一边的对角）。</p></blockquote><p><strong>案例</strong>：</p><ul><li>如图，AB = CD，∠ABE = ∠DCE，BE = CE，求证△ABE ≌ △DCE <ul><li>证明：在△ABE 和△DCE 中 <ul><li>AB = CD（已知）</li><li>∠ABE = ∠DCE（已知）</li><li>BE = CE（已知）</li><li>∴ △ABE ≌ △DCE（SAS）</li></ul></li></ul></li></ul><h4 id="_12-3-角平分线的性质-🟡" tabindex="-1">12.3 角平分线的性质 🟡 <a class="header-anchor" href="#_12-3-角平分线的性质-🟡" aria-label="Permalink to &quot;12.3 角平分线的性质 🟡&quot;">​</a></h4><p><strong>知识点</strong>：角平分线上的点到角两边距离相等；逆定理。</p><p><strong>案例</strong>：</p><ul><li>∠AOB 的平分线上一点 P 到 OA 距离为 3，则 P 到 OB 距离 = <strong>3</strong></li></ul><hr><h3 id="第十三章-轴对称-🟡" tabindex="-1">第十三章 轴对称 🟡 <a class="header-anchor" href="#第十三章-轴对称-🟡" aria-label="Permalink to &quot;第十三章 轴对称 🟡&quot;">​</a></h3><h4 id="_13-1-轴对称" tabindex="-1">13.1 轴对称 <a class="header-anchor" href="#_13-1-轴对称" aria-label="Permalink to &quot;13.1 轴对称&quot;">​</a></h4><p><strong>知识点</strong>：轴对称图形与轴对称的区别与联系。</p><h4 id="_13-2-画轴对称图形" tabindex="-1">13.2 画轴对称图形 <a class="header-anchor" href="#_13-2-画轴对称图形" aria-label="Permalink to &quot;13.2 画轴对称图形&quot;">​</a></h4><h4 id="_13-3-等腰三角形-🔴" tabindex="-1">13.3 等腰三角形 🔴 <a class="header-anchor" href="#_13-3-等腰三角形-🔴" aria-label="Permalink to &quot;13.3 等腰三角形 🔴&quot;">​</a></h4><blockquote><p>🔴 <strong>中考高频</strong>：等腰三角形的性质与判定是重要考点。</p></blockquote><p><strong>知识点</strong>：等边对等角；等角对等边；三线合一；等边三角形。</p><p><strong>案例</strong>：</p><ul><li>等腰三角形两边长为 3 和 7，则周长 = <strong>17</strong>（不能是 3+3+7=13，因为 3+3&lt;7 不满足三边关系）</li><li>等腰三角形一腰上的高与另一腰的夹角为 40°，则顶角 = <strong>50°</strong></li></ul><p><strong>等边三角形</strong> 🟡：</p><ul><li>三边相等、三角都是 60°</li><li>判定：三边相等 或 三个角相等 或 含 60° 的等腰三角形</li></ul><hr><h3 id="第十四章-整式的乘法与因式分解-🟡" tabindex="-1">第十四章 整式的乘法与因式分解 🟡 <a class="header-anchor" href="#第十四章-整式的乘法与因式分解-🟡" aria-label="Permalink to &quot;第十四章 整式的乘法与因式分解 🟡&quot;">​</a></h3><h4 id="_14-1-整式的乘法-🟡" tabindex="-1">14.1 整式的乘法 🟡 <a class="header-anchor" href="#_14-1-整式的乘法-🟡" aria-label="Permalink to &quot;14.1 整式的乘法 🟡&quot;">​</a></h4><p><strong>知识点</strong>：幂的运算（同底数幂乘法、幂的乘方、积的乘方）。</p><p><strong>案例</strong>：</p><ul><li>a³ · a⁵ = <strong>a⁸</strong>（同底数幂相乘，底数不变指数相加）</li><li>(a²)³ = <strong>a⁶</strong>（幂的乘方，底数不变指数相乘）</li><li>(2ab)³ = <strong>8a³b³</strong></li></ul><h4 id="_14-2-乘法公式-🔴" tabindex="-1">14.2 乘法公式 🔴 <a class="header-anchor" href="#_14-2-乘法公式-🔴" aria-label="Permalink to &quot;14.2 乘法公式 🔴&quot;">​</a></h4><p><strong>平方差公式</strong>：(a+b)(a-b) = a² - b²</p><p><strong>完全平方公式</strong>：(a±b)² = a² ± 2ab + b²</p><p><strong>案例</strong>：</p><ul><li>(x+3)(x-3) = <strong>x² - 9</strong></li><li>(2x-1)² = <strong>4x² - 4x + 1</strong></li><li>101² = (100+1)² = 10000 + 200 + 1 = <strong>10201</strong></li><li>99×101 = (100-1)(100+1) = 10000-1 = <strong>9999</strong></li></ul><blockquote><p>⚠️ <strong>中考重点</strong>：乘法公式在因式分解、化简求值中反复使用。</p></blockquote><h4 id="_14-3-因式分解-🔴" tabindex="-1">14.3 因式分解 🔴 <a class="header-anchor" href="#_14-3-因式分解-🔴" aria-label="Permalink to &quot;14.3 因式分解 🔴&quot;">​</a></h4><blockquote><p>🔴 <strong>中考必考</strong>：因式分解是代数运算核心，每年必出。</p></blockquote><p><strong>方法</strong>：</p><ol><li>提公因式法</li><li>公式法（平方差、完全平方）</li><li>十字相乘法（拓展）</li></ol><p><strong>案例</strong>：</p><ul><li>12x²y - 8xy = <strong>4xy(3x - 2)</strong></li><li>x² - 9 = <strong>(x+3)(x-3)</strong></li><li>x² - 6x + 9 = <strong>(x-3)²</strong></li><li>2x² - 8 = <strong>2(x+2)(x-2)</strong></li></ul><blockquote><p>⚠️ <strong>注意</strong>：因式分解必须分解到不能再分（在实数范围内）。</p></blockquote><hr><h3 id="第十五章-分式-🔴" tabindex="-1">第十五章 分式 🔴 <a class="header-anchor" href="#第十五章-分式-🔴" aria-label="Permalink to &quot;第十五章 分式 🔴&quot;">​</a></h3><blockquote><p>🔴 <strong>中考高频</strong>：分式运算与分式方程是广州中考代数部分的重点。</p></blockquote><h4 id="_15-1-分式-🟡" tabindex="-1">15.1 分式 🟡 <a class="header-anchor" href="#_15-1-分式-🟡" aria-label="Permalink to &quot;15.1 分式 🟡&quot;">​</a></h4><p><strong>知识点</strong>：分式有意义的条件（分母 ≠ 0）；分式值为 0 的条件（分子 = 0 且分母 ≠ 0）。</p><p><strong>案例</strong>：</p><ul><li>分式 (x-2)/(x+3) 有意义 → x ≠ <strong>-3</strong></li><li>分式 (x²-4)/(x-2) 值为 0 → x = <strong>-2</strong>（x=2 时分母为 0，舍去）</li></ul><h4 id="_15-2-分式的运算-🔴" tabindex="-1">15.2 分式的运算 🔴 <a class="header-anchor" href="#_15-2-分式的运算-🔴" aria-label="Permalink to &quot;15.2 分式的运算 🔴&quot;">​</a></h4><p><strong>知识点</strong>：分式乘除、加减；通分；混合运算。</p><p><strong>案例</strong>：</p><ul><li>化简：(x²-4)/(x²+2x) ÷ (x-2)/(x+2) <ul><li>= [(x+2)(x-2)] / [x(x+2)] × (x+2)/(x-2)</li><li>= <strong>(x+2)/x</strong></li></ul></li></ul><blockquote><p>⚠️ <strong>中考重点</strong>：分式化简求值是常考题型，常与条件求值结合。</p></blockquote><h4 id="_15-3-分式方程-🟡" tabindex="-1">15.3 分式方程 🟡 <a class="header-anchor" href="#_15-3-分式方程-🟡" aria-label="Permalink to &quot;15.3 分式方程 🟡&quot;">​</a></h4><p><strong>案例</strong>：</p><ul><li>解方程：2/(x-1) = 4/(x²-1) <ul><li>去分母：2(x+1) = 4</li><li>x = <strong>1</strong></li><li>⚠️ 检验：x=1 代入分母 x²-1=0，为增根，<strong>原方程无解</strong></li></ul></li></ul><blockquote><p>⚠️ <strong>必须验根</strong>：分式方程一定要检验增根！</p></blockquote><hr><h2 id="八年级下册" tabindex="-1">八年级下册 <a class="header-anchor" href="#八年级下册" aria-label="Permalink to &quot;八年级下册&quot;">​</a></h2><h3 id="第十六章-二次根式-🟡" tabindex="-1">第十六章 二次根式 🟡 <a class="header-anchor" href="#第十六章-二次根式-🟡" aria-label="Permalink to &quot;第十六章 二次根式 🟡&quot;">​</a></h3><h4 id="_16-1-二次根式" tabindex="-1">16.1 二次根式 <a class="header-anchor" href="#_16-1-二次根式" aria-label="Permalink to &quot;16.1 二次根式&quot;">​</a></h4><p><strong>知识点</strong>：√a ≥ 0（a ≥ 0）；(√a)² = a；√a² = |a|。</p><p><strong>案例</strong>：</p><ul><li>√(x-2) 有意义 → x ≥ <strong>2</strong></li><li>√(-3)² = |-3| = <strong>3</strong></li></ul><h4 id="_16-2-二次根式的乘除-🟡" tabindex="-1">16.2 二次根式的乘除 🟡 <a class="header-anchor" href="#_16-2-二次根式的乘除-🟡" aria-label="Permalink to &quot;16.2 二次根式的乘除 🟡&quot;">​</a></h4><p><strong>案例</strong>：</p><ul><li>√12 = √(4×3) = <strong>2√3</strong></li><li>√6 ÷ √2 = √(6/2) = <strong>√3</strong></li></ul><h4 id="_16-3-二次根式的加减-🟡" tabindex="-1">16.3 二次根式的加减 🟡 <a class="header-anchor" href="#_16-3-二次根式的加减-🟡" aria-label="Permalink to &quot;16.3 二次根式的加减 🟡&quot;">​</a></h4><p><strong>案例</strong>：</p><ul><li>√8 + √18 - √50 = 2√2 + 3√2 - 5√2 = <strong>0</strong></li><li>(√3 + √2)(√3 - √2) = 3 - 2 = <strong>1</strong>（分母有理化常用技巧）</li></ul><hr><h3 id="第十七章-勾股定理-🔴" tabindex="-1">第十七章 勾股定理 🔴 <a class="header-anchor" href="#第十七章-勾股定理-🔴" aria-label="Permalink to &quot;第十七章 勾股定理 🔴&quot;">​</a></h3><blockquote><p>🔴 <strong>中考高频</strong>：勾股定理是必考知识点，常与实际问题结合。</p></blockquote><h4 id="_17-1-勾股定理-🔴" tabindex="-1">17.1 勾股定理 🔴 <a class="header-anchor" href="#_17-1-勾股定理-🔴" aria-label="Permalink to &quot;17.1 勾股定理 🔴&quot;">​</a></h4><p><strong>知识点</strong>：直角三角形中，a² + b² = c²。</p><p><strong>常见勾股数</strong>：</p><table tabindex="0"><thead><tr><th>组合</th><th>倍数关系</th></tr></thead><tbody><tr><td>3, 4, 5</td><td>6-8-10, 9-12-15...</td></tr><tr><td>5, 12, 13</td><td>10-24-26...</td></tr><tr><td>8, 15, 17</td><td>—</td></tr><tr><td>7, 24, 25</td><td>—</td></tr></tbody></table><p><strong>案例</strong>：</p><ul><li>直角三角形两边为 6 和 8，第三边 = ？ <ul><li>若为直角边：c = √(36+64) = <strong>10</strong></li><li>若 8 为斜边：a = √(64-36) = <strong>2√7</strong></li></ul></li></ul><h4 id="_17-2-勾股定理的逆定理-🟡" tabindex="-1">17.2 勾股定理的逆定理 🟡 <a class="header-anchor" href="#_17-2-勾股定理的逆定理-🟡" aria-label="Permalink to &quot;17.2 勾股定理的逆定理 🟡&quot;">​</a></h4><p><strong>知识点</strong>：若 a² + b² = c²，则三角形为直角三角形。</p><p><strong>案例</strong>：</p><ul><li>三边为 5, 12, 13 → 25+144=169 ✓ → <strong>直角三角形</strong></li><li>三边为 4, 5, 6 → 16+25=41 ≠ 36 → <strong>不是直角三角形</strong></li></ul><h4 id="_17-3-勾股定理的应用-🔴" tabindex="-1">17.3 勾股定理的应用 🔴 <a class="header-anchor" href="#_17-3-勾股定理的应用-🔴" aria-label="Permalink to &quot;17.3 勾股定理的应用 🔴&quot;">​</a></h4><p><strong>案例</strong>：</p><ul><li>一架 10 米长的梯子靠在墙上，梯子底端距墙 6 米，梯子顶端高度？ <ul><li>h = √(100-36) = √64 = <strong>8 米</strong></li></ul></li><li>梯子顶端下滑 2 米后，底端外移多少？ <ul><li>新高度 = 6 米，底端距离 = √(100-36) = 8 米，外移 = 8-6 = <strong>2 米</strong></li></ul></li></ul><hr><h3 id="第十八章-平行四边形-🔴" tabindex="-1">第十八章 平行四边形 🔴 <a class="header-anchor" href="#第十八章-平行四边形-🔴" aria-label="Permalink to &quot;第十八章 平行四边形 🔴&quot;">​</a></h3><blockquote><p>🔴 <strong>中考高频</strong>：特殊平行四边形是中考几何大题的常客。</p></blockquote><h4 id="_18-1-平行四边形-🟡" tabindex="-1">18.1 平行四边形 🟡 <a class="header-anchor" href="#_18-1-平行四边形-🟡" aria-label="Permalink to &quot;18.1 平行四边形 🟡&quot;">​</a></h4><p><strong>知识点</strong>：性质——对边平行且相等、对角相等、对角线互相平分。</p><p><strong>判定</strong>：两组对边分别平行/相等、对角线互相平分、一组对边平行且相等。</p><h4 id="_18-2-特殊的平行四边形-🔴" tabindex="-1">18.2 特殊的平行四边形 🔴 <a class="header-anchor" href="#_18-2-特殊的平行四边形-🔴" aria-label="Permalink to &quot;18.2 特殊的平行四边形 🔴&quot;">​</a></h4><table tabindex="0"><thead><tr><th>图形</th><th>性质</th><th>判定</th></tr></thead><tbody><tr><td>矩形</td><td>四个角都是直角；对角线相等</td><td>有一个角是直角的平行四边形；对角线相等的平行四边形</td></tr><tr><td>菱形</td><td>四条边相等；对角线互相垂直</td><td>四条边相等的四边形；对角线互相垂直的平行四边形</td></tr><tr><td>正方形</td><td>具有矩形和菱形的所有性质</td><td>既是矩形又是菱形</td></tr></tbody></table><p><strong>案例</strong>：</p><ul><li>菱形对角线长为 6 和 8，则面积 = (6×8)/2 = <strong>24</strong>，边长 = √(9+16) = <strong>5</strong></li><li>矩形对角线长 10，一边长 6，则面积 = 6 × √(100-36) = 6×8 = <strong>48</strong></li></ul><blockquote><p>⚠️ <strong>中考趋势</strong>：广州中考近年在特殊平行四边形上常出综合题，结合全等三角形与旋转变换。</p></blockquote><hr><h3 id="第十九章-一次函数-🔴🔴" tabindex="-1">第十九章 一次函数 🔴🔴 <a class="header-anchor" href="#第十九章-一次函数-🔴🔴" aria-label="Permalink to &quot;第十九章 一次函数 🔴🔴&quot;">​</a></h3><blockquote><p>🔴🔴 <strong>中考核心</strong>：一次函数是初中函数的起点，也是中考重中之重。广州中考压轴题常涉及一次函数与几何综合。</p></blockquote><h4 id="_19-1-函数-🟡" tabindex="-1">19.1 函数 🟡 <a class="header-anchor" href="#_19-1-函数-🟡" aria-label="Permalink to &quot;19.1 函数 🟡&quot;">​</a></h4><p><strong>知识点</strong>：函数的概念；自变量、因变量；函数值。</p><p><strong>案例</strong>：</p><ul><li>y = 2x + 1 中，x = 3 时 y = <strong>7</strong>；y = 5 时 x = <strong>2</strong></li></ul><h4 id="_19-2-一次函数-🔴" tabindex="-1">19.2 一次函数 🔴 <a class="header-anchor" href="#_19-2-一次函数-🔴" aria-label="Permalink to &quot;19.2 一次函数 🔴&quot;">​</a></h4><p><strong>知识点</strong>：y = kx + b（k≠0）；k&gt;0 时 y 随 x 增大而增大，k&lt;0 时减小。</p><p><strong>案例</strong>：</p><ul><li>y = -2x + 6 与 x 轴交点：令 y=0 → x=3，与 y 轴交点：(0, 6)</li><li>两点确定一次函数：过 (1,3) 和 (2,5) <ul><li>k = (5-3)/(2-1) = 2，b = 3-2 = 1 → y = <strong>2x + 1</strong></li></ul></li></ul><h4 id="_19-3-课题学习-选择方案" tabindex="-1">19.3 课题学习：选择方案 <a class="header-anchor" href="#_19-3-课题学习-选择方案" aria-label="Permalink to &quot;19.3 课题学习：选择方案&quot;">​</a></h4><p><strong>案例</strong>：</p><ul><li>A 方案：月租 20 元，通话 0.1 元/分钟</li><li>B 方案：无月租，通话 0.3 元/分钟 <ul><li>A：y = 0.1x + 20；B：y = 0.3x</li><li>令 0.1x+20 = 0.3x → x = 100</li><li>通话 &gt; 100 分钟选 A，&lt; 100 分钟选 B</li></ul></li></ul><h4 id="_19-4-一次函数与方程、不等式-🔴" tabindex="-1">19.4 一次函数与方程、不等式 🔴 <a class="header-anchor" href="#_19-4-一次函数与方程、不等式-🔴" aria-label="Permalink to &quot;19.4 一次函数与方程、不等式 🔴&quot;">​</a></h4><blockquote><p>🔴 <strong>重要联系</strong>：</p></blockquote><table tabindex="0"><thead><tr><th>数学对象</th><th>一次函数视角</th></tr></thead><tbody><tr><td>一元一次方程 kx+b=0</td><td>函数 y=kx+b 与 x 轴交点</td></tr><tr><td>一元一次不等式 kx+b&gt;0</td><td>函数图像在 x 轴上方部分</td></tr><tr><td>二元一次方程组</td><td>两个一次函数图像的交点</td></tr></tbody></table><hr><h3 id="第二十章-数据的分析-🟡" tabindex="-1">第二十章 数据的分析 🟡 <a class="header-anchor" href="#第二十章-数据的分析-🟡" aria-label="Permalink to &quot;第二十章 数据的分析 🟡&quot;">​</a></h3><h4 id="_20-1-数据的集中趋势-🟡" tabindex="-1">20.1 数据的集中趋势 🟡 <a class="header-anchor" href="#_20-1-数据的集中趋势-🟡" aria-label="Permalink to &quot;20.1 数据的集中趋势 🟡&quot;">​</a></h4><p><strong>知识点</strong>：平均数、中位数、众数。</p><p><strong>案例</strong>：</p><ul><li>数据 2, 3, 5, 7, 8：平均数 = 5，中位数 = 5，众数 = 无</li><li>数据 2, 3, 3, 5, 7：众数 = <strong>3</strong></li></ul><h4 id="_20-2-数据的波动程度-🟢" tabindex="-1">20.2 数据的波动程度 🟢 <a class="header-anchor" href="#_20-2-数据的波动程度-🟢" aria-label="Permalink to &quot;20.2 数据的波动程度 🟢&quot;">​</a></h4><p><strong>知识点</strong>：方差——衡量数据波动大小，方差越小越稳定。</p><p><strong>案例</strong>：</p><ul><li>甲组：2, 4, 6, 8, 10 → 平均 6，方差 = [(4+0+4+16+36)/5] = <strong>8</strong></li><li>乙组：5, 5, 6, 6, 8 → 平均 6，方差 = <strong>1.6</strong></li><li>乙组数据更稳定</li></ul><blockquote><p>💡 <strong>中考提示</strong>：广州中考统计题一般出一道选择题（3分），难度不大，注意概念区分。</p></blockquote><hr><h2 id="初二重点总结" tabindex="-1">初二重点总结 <a class="header-anchor" href="#初二重点总结" aria-label="Permalink to &quot;初二重点总结&quot;">​</a></h2><h3 id="广州中考初二相关考点权重" tabindex="-1">广州中考初二相关考点权重 <a class="header-anchor" href="#广州中考初二相关考点权重" aria-label="Permalink to &quot;广州中考初二相关考点权重&quot;">​</a></h3><table tabindex="0"><thead><tr><th>章节</th><th>中考占比</th><th>重要性</th><th>说明</th></tr></thead><tbody><tr><td>一次函数</td><td>约 10-12%</td><td>🔴🔴</td><td>压轴题常客</td></tr><tr><td>全等三角形</td><td>约 8-10%</td><td>🔴🔴</td><td>几何证明核心</td></tr><tr><td>特殊平行四边形</td><td>约 6-8%</td><td>🔴</td><td>综合题高频</td></tr><tr><td>勾股定理</td><td>约 5-6%</td><td>🔴</td><td>应用题必出</td></tr><tr><td>因式分解</td><td>约 4-5%</td><td>🔴</td><td>代数运算基础</td></tr><tr><td>分式</td><td>约 4-5%</td><td>🔴</td><td>化简求值常考</td></tr><tr><td>三角形</td><td>约 4-5%</td><td>🟡</td><td>内角和外角</td></tr><tr><td>二次根式</td><td>约 3%</td><td>🟡</td><td>运算基础</td></tr><tr><td>等腰三角形</td><td>约 3%</td><td>🟡</td><td>结合全等考</td></tr><tr><td>数据分析</td><td>约 2-3%</td><td>🟡</td><td>选择题</td></tr><tr><td>轴对称</td><td>约 2%</td><td>🟢</td><td>作图题偶出</td></tr></tbody></table><h3 id="初二学习建议" tabindex="-1">初二学习建议 <a class="header-anchor" href="#初二学习建议" aria-label="Permalink to &quot;初二学习建议&quot;">​</a></h3><ol><li><strong>全等三角形是重中之重</strong> — 熟练掌握五种判定方法，学会书写规范证明</li><li><strong>一次函数开启函数大门</strong> — 理解数形结合思想，学会从图像中读信息</li><li><strong>因式分解要多练</strong> — 这项技能贯穿整个初中代数</li><li><strong>勾股定理重在应用</strong> — 广州中考喜欢考实际情境中的勾股问题</li><li><strong>特殊四边形要理解关系</strong> — 矩形→菱形→正方形的包含关系和判定链</li></ol>',153)])])}const p=r(n,[["render",e]]);export{b as __pageData,p as default};
